export declare const typeDefs = "\n  # Scalar types untuk tipe data khusus\n  scalar Date\n  scalar ObjectId\n\n  # Base Query - semua query akan didefinisikan disini\n  type Query {\n    # Test query untuk memastikan server berjalan\n    hello: String!\n  }\n\n  # Base Mutation - semua mutation akan didefinisikan disini\n  type Mutation {\n    # Test mutation untuk memastikan server berjalan\n    testMutation: String\n  }\n\n  # Base Subscription - semua subscription akan didefinisikan disini\n  type Subscription {\n    # Test subscription untuk memastikan server berjalan\n    testSubscription: String\n  }\n\n  \n    #  Input untuk register pengguna baru\n    input RegisterInput {\n        email: String!\n        noHP: String!\n        namaLengkap: String!\n        password: String!\n    }\n\n    # Input unttuk  login pengguna\n    input LoginInput {\n        email: String!\n        password: String!\n    }\n\n    # Input untuk verifikasi OTP\n    input VerifyOTPInput {\n        email: String!\n        otp: String!\n    }\n\n    # Input untuk resend OTP\n    input ResendOTPInput {\n        email: String!\n    }\n\n    # Input untuk update profil pengguna\n    input UpdateProfileInput {\n        namaLengkap: String\n        noHP: String\n    }\n    \n    # Input untuk update password pengguna\n    input UpdatePasswordInput {\n        currentPassword: String\n        newPassword: String!\n    }\n    \n    # Type untuk respons auth (login/register)\n    type AuthPayload {\n        success: Boolean!\n        message: String!\n        token: String\n        user: Pengguna\n    }\n\n    # Type untuk data pengguna\n    type Pengguna {\n        id: ObjectId!\n        email: String!\n        noHP: String!\n        namaLengkap: String!\n        isVerified: Boolean!\n        profilePicture: String\n        authProvider: String!\n        createdAt: Date!\n        updatedAt: Date!\n    }\n\n    #Response untuk operasi CRUD umum\n    type StandardResponse {\n        success: Boolean!\n        message: String!\n        data: Pengguna\n    }\n\n    extend type Query {\n        # Mendapatkan data pengguna yang sedang login\n        me: Pengguna\n    }\n\n    extend type Mutation {\n        # Register pengguna baru\n        register(input: RegisterInput!): AuthPayload!\n        # Login pengguna\n        login(input: LoginInput!): AuthPayload!\n        # Logout\n        logout: StandardResponse!\n\n        # Verifikasi OTP\n        verifyOTP(input: VerifyOTPInput!): AuthPayload!\n        # Resend OTP\n        resendOTP(input: ResendOTPInput!): StandardResponse!\n\n        # Update profil pengguna\n        updateProfile(input: UpdateProfileInput!): StandardResponse!\n        # Update password pengguna\n        updatePassword(input: UpdatePasswordInput!): StandardResponse!\n    }\n\n  \n    #Enum untuk status pembayaran\n    enum PaymentStatus {\n        PENDING\n        SETTLEMENT\n        CANCEL\n        EXPIRE\n        REFUND\n        CHARGEBACK\n        FRAUD\n    }\n\n    # Type untuk data tagihan\n    type Tagihan {\n        id: ObjectId!\n        idMeteran: ObjectId!\n        meteran: Meter\n        periode: String!\n        penggunaanSebelum: Float!\n        penggunaanSesudah: Float!\n        TotalPemakaian: Float!\n        biaya: Float!\n        totalBiaya: Float!\n        statusPembayaran: PaymentStatus!\n        tanggalPembayaran: Date\n        metodePembayaran: String\n        tenggatWaktu: Date!\n        menunggak: Boolean!\n        denda: Float!\n        createdAt: Date!\n        updatedAt: Date!\n    }\n\n    # Input untuk filter tagiihan\n    input TagihanFilterInput {\n        idMeteran: ObjectId\n        periode: String\n        statusPembayaran: PaymentStatus\n        menunggak: Boolean\n    }\n\n    # Response untuk operasi tagihan\n    type TagihanResponse {\n        success: Boolean!\n        message: String!\n        data: Tagihan\n    }\n\n    type TagihanListResponse {\n        success: Boolean!\n        message: String!    \n        data: [Tagihan]\n        total: Int\n    }\n\n    extend type Query {\n        #  Mendapatkan semua tagihan pengguna\n        tagihanList(filter: TagihanFilterInput): TagihanListResponse!\n        # Mendapatkan detail tagihan berdasarkan ID\n        tagihan(id: ObjectId!): TagihanResponse!\n        # Mendapatkan tagihan aktif (belum dibayar)\n        tagihanAktif: TagihanResponse!\n        # Mendapatkan riwayat tagihan yang sudah dibayar\n        tagihanRiwayat: TagihanListResponse!\n    }\n\n    extend type Mutation {\n        # Bayar tagihan\n        bayarTagihan(id: ObjectId!, metodePembayaran: String!): TagihanResponse!\n    }\n\n  \n    #Enun untuk jenis Laporan\n        enum JenisLaporan {\n        AIR_TIDAK_MENGALIR\n        AIR_KERUH\n        KEBOCORAN_PIPA\n        METERAN_BERMASALAH\n        KENDALA_LAINNYA\n    }\n\n    # Enum untuk status laporan pelanggan\n    enum WorkStatusPelanggan {\n        DITUNDA\n        DITUGASKAN\n        DITINJAU_ADMIN\n        SEDANG_DIKERJAKAN\n        SELESAI\n        DIBATALKAN\n    }\n    \n    # Type untuk data laporan\n    type Laporan {\n        id: ObjectId!\n        idPengguna: ObjectId!\n        pengguna: Pengguna\n        namaLaporan: String!\n        masalah: String!\n        alamat: String!\n        imageURL: [String]!\n        jenisLaporan: JenisLaporan!\n        catatan: String\n        koordinat: ObjectId!\n        geoLokasi: GeoLokasi\n        status: WorkStatusPelanggan!\n        createdAt: Date!\n        updatedAt: Date!\n    }   \n    \n    # Input untuk membuat laporan baru\n    input CreateLaporanInput {\n        namaLaporan: String!\n        masalah: String!\n        alamat: String!\n        imageURL: [String]\n        jenisLaporan: JenisLaporan!\n        catatan: String\n        langitude: Float!\n        longitude: Float!\n    }\n        \n    # Input untuk update laporan\n    input UpdateLaporanInput {\n        namaLaporan: String\n        masalah: String\n        alamat: String\n        imageURL: [String!]\n        catatan: String\n    }\n    \n     # Input untuk filter laporan\n  input LaporanFilterInput {\n    jenisLaporan: JenisLaporan\n    status: WorkStatusPelanggan\n  }\n\n  # Response untuk operasi laporan\n  type LaporanResponse {\n    success: Boolean!\n    message: String!\n    data: Laporan\n  }\n\n  type LaporanListResponse {\n    success: Boolean!\n    message: String!\n    data: [Laporan!]\n    total: Int\n  }\n\n  extend type Query {\n    # Mendapatkan semua laporan pengguna\n    laporanList(filter: LaporanFilterInput): LaporanListResponse!\n    # Mendapatkan detail laporan berdasarkan ID\n    laporanById(id: ObjectId!): LaporanResponse!\n    # Mendapatkan laporan aktif (belum selesai)\n    laporanAktif: LaporanListResponse!\n  }\n\n  extend type Mutation {\n    # Membuat laporan baru\n    createLaporan(input: CreateLaporanInput!): LaporanResponse!\n    # Update laporan (hanya jika status masih DITUNDA)\n    updateLaporan(id: ObjectId!, input: UpdateLaporanInput!): LaporanResponse!\n    # Batalkan laporan\n    batalkanLaporan(id: ObjectId!): LaporanResponse!\n  }\n\n  \n  # Enum untuk kategori notifikasi\n  enum NotifikasiKategori {\n    PEMBAYARAN\n    INFORMASI\n  }\n\n  # Type untuk data notifikasi\n  type Notifikasi {\n    id: ObjectId!\n    idPelanggan: ObjectId!\n    idAdmin: ObjectId\n    idTeknisi: ObjectId\n    judul: String!\n    pesan: String!\n    kategori: NotifikasiKategori!\n    link: String\n    createdAt: Date!\n    updatedAt: Date!\n  }\n\n  # Input untuk filter notifikasi\n  input NotifikasiFilterInput {\n    kategori: NotifikasiKategori\n  }\n\n  # Response untuk operasi notifikasi\n  type NotifikasiResponse {\n    success: Boolean!\n    message: String!\n    data: Notifikasi\n  }\n\n  type NotifikasiListResponse {\n    success: Boolean!\n    message: String!\n    data: [Notifikasi!]\n    total: Int\n    unreadCount: Int\n  }\n\n  extend type Query {\n    # Mendapatkan semua notifikasi pengguna\n    notifikasiList(filter: NotifikasiFilterInput): NotifikasiListResponse!\n    # Mendapatkan detail notifikasi berdasarkan ID\n    notifikasiById(id: ObjectId!): NotifikasiResponse!\n  }\n\n  \n  # Type untuk data meteran\n  type Meter {\n    id: ObjectId!\n    idKelompokPelanggan: ObjectId!\n    idKoneksiData: ObjectId!\n    koneksiData: KoneksiData\n    nomorMeteran: String!\n    nomorAkun: String!\n    createdAt: Date!\n    updatedAt: Date!\n  }\n\n  # Response untuk operasi meter\n  type MeterResponse {\n    success: Boolean!\n    message: String!\n    data: Meter\n  }\n\n  type MeterListResponse {\n    success: Boolean!\n    message: String!\n    data: [Meter!]\n    total: Int\n  }\n\n  extend type Query {\n    # Mendapatkan semua meteran pengguna\n    meterList: MeterListResponse!\n    # Mendapatkan detail meteran berdasarkan ID\n    meterById(id: ObjectId!): MeterResponse!\n    # Mendapatkan meteran berdasarkan nomor meteran\n    meterByNomor(nomorMeteran: String!): MeterResponse!\n  }\n\n  \n  # Enum status pengajuan koneksi\n  enum StatusPengajuan {\n    PENDING\n    APPROVED\n    REJECTED\n  }\n\n  # Type untuk data koneksi\n  type KoneksiData {\n    id: ObjectId!\n    idPelanggan: ObjectId!\n    pengguna: Pengguna\n    statusPengajuan: StatusPengajuan!\n    alasanPenolakan: String\n    tanggalVerifikasi: Date\n    nik: String!\n    nikUrl: String!\n    noKK: String!\n    kkUrl: String!\n    imb: String!\n    imbUrl: String!\n    alamat: String!\n    kelurahan: String!\n    kecamatan: String!\n    luasBangunan: Float!\n    createdAt: Date!\n    updatedAt: Date!\n  }\n\n  # Input untuk membuat koneksi data baru\n  input CreateKoneksiDataInput {\n    nik: String!\n    nikUrl: String!\n    noKK: String!\n    kkUrl: String!\n    imb: String!\n    imbUrl: String!\n    alamat: String!\n    kelurahan: String!\n    kecamatan: String!\n    luasBangunan: Float!\n  }\n\n  # Input untuk update koneksi data\n  input UpdateKoneksiDataInput {\n    nikUrl: String\n    kkUrl: String\n    imbUrl: String\n    alamat: String\n    kelurahan: String\n    kecamatan: String\n    luasBangunan: Float\n  }\n\n  # Response untuk cek status pengajuan\n  type StatusPengajuanResponse {\n    success: Boolean!\n    message: String!\n    statusPengajuan: StatusPengajuan\n    alasanPenolakan: String\n    tanggalVerifikasi: Date\n    canSubmit: Boolean!\n    subTahap: String\n    jumlahRAB: Float\n    snapRedirectUrl: String\n    urlRab: String\n    catatanRab: String\n  }\n\n  # Response untuk operasi koneksi data\n  type KoneksiDataResponse {\n    success: Boolean!\n    message: String!\n    data: KoneksiData\n  }\n\n  extend type Query {\n    # Mendapatkan koneksi data pengguna\n    koneksiData: KoneksiDataResponse!\n    # Mendapatkan detail koneksi data berdasarkan ID\n    koneksiDataById(id: ObjectId!): KoneksiDataResponse!\n    # Cek status pengajuan koneksi pengguna\n    cekStatusPengajuan: StatusPengajuanResponse!\n  }\n\n  extend type Mutation {\n    # Membuat koneksi data baru (pendaftaran langganan PDAM)\n    createKoneksiData(input: CreateKoneksiDataInput!): KoneksiDataResponse!\n    # Update koneksi data\n    updateKoneksiData(input: UpdateKoneksiDataInput!): KoneksiDataResponse!\n  }\n\n  \n  # Type untuk data geo lokasi\n  type GeoLokasi {\n    id: ObjectId!\n    idLaporan: ObjectId!\n    latitude: Float!\n    longitude: Float!\n    createdAt: Date!\n    updatedAt: Date!\n  }\n\n  \n  # Type untuk data riwayat penggunaan\n  type RiwayatPenggunaan {\n    id: ObjectId!\n    meteranId: ObjectId!\n    meteran: Meter\n    penggunaanAir: Float!\n    createdAt: Date!\n    updatedAt: Date!\n  }\n\n  # Response untuk operasi riwayat penggunaan\n  type RiwayatPenggunaanListResponse {\n    success: Boolean!\n    message: String!\n    data: [RiwayatPenggunaan!]\n    total: Int\n  }\n\n  extend type Query {\n    # Mendapatkan riwayat penggunaan air\n    riwayatPenggunaan(meteranId: ObjectId!): RiwayatPenggunaanListResponse!\n  }\n\n  \n    # Enum untuk status pembayaran di Midtrans\n    enum StatusPembayaran {\n        Pending\n        Settlement\n        Cancel\n        Expire\n        Refund\n    }\n\n    # Type untuk data pembayaran\n    type Pembayaran {\n        id: ObjectId!\n        idTagihan: ObjectId!\n        tagihan: Tagihan\n        idPengguna: ObjectId!\n        midtransOrderId: String!\n        midtransTransactionId: String\n        snapToken: String!\n        snapRedirectUrl: String!\n        metodePembayaran: String\n        jumlahBayar: Float!\n        statusPembayaran: StatusPembayaran!\n        tanggalBayar: Date\n        createdAt: Date!\n        updatedAt: Date!\n    }\n\n    # Response untuk create payment (berisi snap token)\n    type CreatePaymentData {\n        pembayaran: Pembayaran!\n        snapToken: String!\n        snapRedirectUrl: String!\n    }\n\n    type CreatePaymentResponse {\n        success: Boolean!\n        message: String!\n        data: CreatePaymentData\n    }\n\n    # Response untuk operasi pembayaran\n    type PembayaranResponse {\n        success: Boolean!\n        message: String!\n        data: Pembayaran\n    }\n\n    type PembayaranListResponse {\n        success: Boolean!\n        message: String!\n        data: [Pembayaran]\n        total: Int\n    }\n\n    extend type Query {\n        # Mendapatkan riwayat pembayaran user\n        pembayaranList(limit: Int, offset: Int): PembayaranListResponse!\n        # Mendapatkan detail pembayaran\n        pembayaran(id: ObjectId!): PembayaranResponse!\n    }\n\n    extend type Mutation {\n        # Buat pembayaran baru (dapat snap token untuk Midtrans)\n        buatPembayaran(tagihanId: ObjectId!): CreatePaymentResponse!\n    }\n\n  \n  # ==========================================\n  # TYPE DEFINITIONS\n  # ==========================================\n\n  \"\"\"\n  Pembacaan terakhir dari sensor IoT\n  Data disimpan di Redis: usage:{meteranId}:latest\n  \"\"\"\n  type LatestReading {\n    volume: Float!        # Volume pembacaan dalam liter\n    timestamp: String!    # Waktu pembacaan ISO format\n    meteranId: String!    # ID meteran\n  }\n\n  \"\"\"\n  Data penggunaan per hari dalam satu bulan\n  Format: { \"01\": 45.7, \"02\": 38.2, ... }\n  \"\"\"\n  type DailyUsageEntry {\n    tanggal: String!      # Tanggal (DD)\n    liter: Float!         # Penggunaan dalam liter\n  }\n\n  \"\"\"\n  Data penggunaan untuk satu bulan\n  Bisa dari Redis (bulan ini) atau MongoDB (bulan lalu)\n  \"\"\"\n  type MonthlyUsageData {\n    periode: String!              # Format: \"YYYY-MM\"\n    totalPenggunaan: Float!       # Total liter dalam bulan\n    dataHarian: [DailyUsageEntry!]! # Breakdown per hari\n    sumber: String!               # \"redis\" atau \"mongodb\"\n  }\n\n  \"\"\"\n  Statistik perbandingan dengan bulan sebelumnya\n  \"\"\"\n  type UsageComparison {\n    bulanIni: Float!      # Total penggunaan bulan ini (liter)\n    bulanLalu: Float!     # Total penggunaan bulan lalu (liter)\n    selisih: Float!       # Selisih (positif = naik, negatif = turun)\n    persentase: Float!    # Persentase perubahan\n    status: String!       # \"naik\", \"turun\", atau \"sama\"\n  }\n\n  \"\"\"\n  Prediksi penggunaan sampai akhir bulan\n  Dihitung berdasarkan rata-rata harian saat ini\n  \"\"\"\n  type UsagePrediction {\n    hariTerlewati: Int!       # Jumlah hari yang sudah lewat\n    hariTersisa: Int!         # Jumlah hari tersisa dalam bulan\n    totalHari: Int!           # Total hari dalam bulan\n    rataRataHarian: Float!    # Rata-rata penggunaan per hari (liter)\n    prediksiAkhirBulan: Float! # Prediksi total akhir bulan (liter)\n    penggunaanSaatIni: Float! # Penggunaan sampai saat ini (liter)\n  }\n\n  \"\"\"\n  Info kelompok pelanggan untuk tampilan tagihan\n  \"\"\"\n  type KelompokInfo {\n    kode: String!         # Kode kelompok (RT-1, N-2, dll)\n    nama: String!         # Nama lengkap kelompok\n    kategori: String!     # Kategori (Sosial, Non Niaga, Niaga, dll)\n  }\n\n  \"\"\"\n  Estimasi tagihan berdasarkan tarif PDAM\n  Dihitung dari prediksi pemakaian akhir bulan\n  \"\"\"\n  type BillingEstimate {\n    pemakaianM3: Float!       # Pemakaian dalam m\u00B3 (kubik)\n    tarifRendah: Float!       # Tarif 0-10 m\u00B3 (per m\u00B3)\n    tarifTinggi: Float!       # Tarif >10 m\u00B3 (per m\u00B3)\n    batasRendah: Float!       # Batas pemakaian rendah (biasanya 10 m\u00B3)\n    biayaPemakaian: Float!    # Biaya pemakaian air\n    biayaBeban: Float!        # Biaya beban bulanan\n    totalEstimasi: Float!     # Total estimasi tagihan\n    kelompok: KelompokInfo!   # Info kelompok pelanggan\n  }\n\n  \"\"\"\n  Evaluasi kategori penggunaan air\n  Berdasarkan rata-rata bulanan:\n  - hemat: < 5 m\u00B3/bulan\n  - normal: 5-15 m\u00B3/bulan\n  - boros: > 15 m\u00B3/bulan\n  \"\"\"\n  type UsageEvaluation {\n    kategori: String!         # \"hemat\", \"normal\", atau \"boros\"\n    deskripsi: String!        # Penjelasan kategori\n    rataRataBulanan: Float!   # Rata-rata penggunaan bulanan (liter)\n    batasHemat: Float!        # Batas kategori hemat (liter)\n    batasBoros: Float!        # Batas kategori boros (liter)\n  }\n\n  \"\"\"\n  Info dasar meteran untuk dashboard\n  \"\"\"\n  type MeteranInfo {\n    id: String!               # ID meteran\n    nomorMeteran: String!     # Nomor fisik meteran\n    nomorAkun: String!        # Nomor akun pelanggan\n  }\n\n  \"\"\"\n  Entry untuk chart harian (7 hari terakhir)\n  \"\"\"\n  type ChartEntry {\n    tanggal: String!          # Format: \"DD/MM\"\n    liter: Float!             # Penggunaan dalam liter\n  }\n\n  \"\"\"\n  Data lengkap untuk dashboard monitoring\n  Menggabungkan data dari Redis (real-time) dan MongoDB (historis)\n  \"\"\"\n  type MonitoringDashboardData {\n    # Info Meteran\n    meteran: MeteranInfo!\n    \n    # Pembacaan terakhir dari sensor IoT\n    latestReading: LatestReading\n    \n    # Penggunaan bulan ini (dari Redis)\n    bulanIni: MonthlyUsageData\n    \n    # Penggunaan bulan lalu (dari MongoDB)\n    bulanLalu: MonthlyUsageData\n    \n    # Total keseluruhan sepanjang waktu\n    totalKeseluruhan: Float!\n    \n    # Rata-rata bulanan (6 bulan terakhir)\n    rataRataBulanan: Float!\n    \n    # Perbandingan bulan ini vs bulan lalu\n    perbandingan: UsageComparison\n    \n    # Prediksi penggunaan akhir bulan\n    prediksi: UsagePrediction\n    \n    # Evaluasi kategori penggunaan\n    evaluasi: UsageEvaluation!\n    \n    # Estimasi tagihan bulan ini\n    estimasiTagihan: BillingEstimate\n    \n    # Data untuk chart 7 hari terakhir\n    chartHarian: [ChartEntry!]!\n  }\n\n  # ==========================================\n  # RESPONSE TYPES\n  # ==========================================\n\n  \"\"\"\n  Response untuk query dashboard monitoring\n  \"\"\"\n  type MonitoringDashboardResponse {\n    success: Boolean!\n    message: String!\n    data: MonitoringDashboardData\n  }\n\n  \"\"\"\n  Response untuk query history\n  \"\"\"\n  type MonitoringHistoryResponse {\n    success: Boolean!\n    message: String!\n    data: [MonthlyUsageData!]\n  }\n\n  \"\"\"\n  Entry data per jam\n  \"\"\"\n  type HourlyEntry {\n    jam: String!              # Format: \"HH\" (00-23)\n    liter: Float!             # Penggunaan dalam liter\n  }\n\n  \"\"\"\n  Response untuk query data per jam\n  \"\"\"\n  type MonitoringHourlyResponse {\n    success: Boolean!\n    message: String!\n    data: [HourlyEntry!]\n  }\n\n  \"\"\"\n  Response untuk query data penggunaan bulanan per periode\n  \"\"\"\n  type MonitoringMonthlyUsageResponse {\n    success: Boolean!\n    message: String!\n    data: MonthlyUsageData\n  }\n\n  # ==========================================\n  # QUERIES\n  # ==========================================\n\n  extend type Query {\n    \"\"\"\n    Mendapatkan data dashboard monitoring lengkap\n    Memerlukan autentikasi\n    \n    @param meteranId - ID meteran yang akan dimonitor\n    @returns MonitoringDashboardResponse dengan semua data monitoring\n    \"\"\"\n    monitoringDashboard(meteranId: ObjectId!): MonitoringDashboardResponse!\n\n    \"\"\"\n    Mendapatkan riwayat penggunaan beberapa bulan terakhir\n    \n    @param meteranId - ID meteran\n    @param jumlahBulan - Jumlah bulan ke belakang (default: 6)\n    @returns MonitoringHistoryResponse dengan array data bulanan\n    \"\"\"\n    monitoringHistory(\n      meteranId: ObjectId!, \n      jumlahBulan: Int\n    ): MonitoringHistoryResponse!\n\n    \"\"\"\n    Mendapatkan data penggunaan per jam untuk tanggal tertentu\n    \n    @param meteranId - ID meteran\n    @param tanggal - Tanggal dalam format YYYY-MM-DD\n    @returns MonitoringHourlyResponse dengan breakdown per jam\n    \"\"\"\n    monitoringHourly(\n      meteranId: String!, \n      tanggal: String!\n    ): MonitoringHourlyResponse!\n\n    \"\"\"\n    Mendapatkan data penggunaan harian untuk bulan tertentu\n    Otomatis memilih sumber: Redis (bulan ini) atau MongoDB (bulan lalu)\n    \n    @param meteranId - ID meteran\n    @param periode - Periode bulan dalam format YYYY-MM\n    @returns MonitoringMonthlyUsageResponse dengan data harian\n    \"\"\"\n    monitoringMonthlyUsage(\n      meteranId: ObjectId!,\n      periode: String!\n    ): MonitoringMonthlyUsageResponse!\n  }\n\n  \n  # Type untuk RAB (Rencana Anggaran Biaya)\n  type RAB {\n    id: ObjectId!\n    idKoneksiData: ObjectId!\n    totalBiaya: Float\n    statusPembayaran: String!\n    orderId: String\n    paymentUrl: String\n    urlRab: String\n    catatan: String\n    createdAt: Date!\n    updatedAt: Date!\n  }\n\n  # Response untuk operasi RAB\n  type RABResponse {\n    success: Boolean!\n    message: String!\n    data: RAB\n  }\n\n  # Response untuk pembayaran RAB\n  type RABPaymentResponse {\n    success: Boolean!\n    message: String!\n    snapToken: String\n    snapRedirectUrl: String\n  }\n\n  extend type Query {\n    # Get RAB untuk koneksi data user yang sedang login\n    getMyRAB: RABResponse!\n  }\n\n  extend type Mutation {\n    # Buat pembayaran RAB via Midtrans\n    createRABPayment: RABPaymentResponse!\n  }\n\n";
//# sourceMappingURL=index.d.ts.map